const satisfaction = $input.item.json["On a scale of 1–5, how satisfied are you with your job?  "];
const managerSupport = $input.item.json["How would you rate your manager's support and feedback?  "];
const workHours = String($input.item.json[" How many hours do you work on average per day?  "] || "");
const careerGrowth = $input.item.json["Do you see good career growth opportunities in the company?  "];
const leaveIntent = $input.item.json["How likely are you to leave the company in the next 6 months?  "];

let riskScore = 0;

// Low satisfaction (1-2 = high risk)
if (satisfaction <= 2) riskScore += 25;
else if (satisfaction === 3) riskScore += 10;

// Poor manager support (1-2 = high risk)
if (managerSupport <= 2) riskScore += 20;
else if (managerSupport === 3) riskScore += 10;

// Long working hours
if (workHours.includes("10")) riskScore += 20;
else if (workHours.includes("8-9") || workHours.includes("9")) riskScore += 10;

// No career growth
if (careerGrowth === "No") riskScore += 20;

// High leave intent (4-5 = high risk)
if (leaveIntent >= 4) riskScore += 15;

// Determine risk level
let riskLevel = "Low";
if (riskScore >= 60) riskLevel = "High";
else if (riskScore >= 30) riskLevel = "Medium";

return {
  ...($input.item.json),
  riskScore,
  riskLevel
};

